/**
 * Integration tests for the full notification pipeline.
 *
 * Tests end-to-end notification delivery through:
 *   NotificationService → Adapters (email, SMS, webhook) → Preferences → History
 *
 * Unlike unit tests, these wire up the real components (with in-memory transports)
 * and verify the full flow from send() through adapter delivery to history logging.
 */

import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { EventBus } from '../../src/events/event-bus.js';
import { NotificationService, resetNotificationIdCounter } from '../../src/services/notification.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import { SMSAdapter } from '../../src/adapters/sms.adapter.js';
import { WebhookAdapter } from '../../src/adapters/webhook.adapter.js';
import { PreferencesService, resetPreferencesIdCounter } from '../../src/services/preferences.service.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import { NotificationHistoryService, resetNotificationLogIdCounter } from '../../src/services/notification-history.service.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import type { NotificationPayload } from '../../src/models/notification.js';

describe('Notification Pipeline Integration', () => {
  let db: Database;
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let emailAdapter: EmailAdapter;
  let smsAdapter: SMSAdapter;
  let webhookAdapter: WebhookAdapter;
  let preferencesService: PreferencesService;
  let preferencesRepo: PreferencesRepository;
  let historyService: NotificationHistoryService;
  let logRepo: NotificationLogRepository;

  beforeEach(() => {
    resetNotificationIdCounter();
    resetPreferencesIdCounter();
    resetNotificationLogIdCounter();

    db = new Database();
    eventBus = new EventBus();

    // Wire up the full pipeline
    notificationService = new NotificationService(eventBus);

    emailAdapter = new EmailAdapter();
    smsAdapter = new SMSAdapter();
    webhookAdapter = new WebhookAdapter();
    notificationService.registerAdapter(emailAdapter);
    notificationService.registerAdapter(smsAdapter);
    notificationService.registerAdapter(webhookAdapter);

    preferencesRepo = new PreferencesRepository(db);
    preferencesService = new PreferencesService(preferencesRepo);
    notificationService.setPreferencesService(preferencesService);

    logRepo = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(logRepo, eventBus);
    notificationService.setHistoryService(historyService);
  });

  // --- Helper ---
  function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
    return {
      channel: 'email',
      notificationType: 'order-confirmation',
      recipient: 'alice@example.com',
      subject: 'Order Confirmed',
      body: 'Your order has been placed.',
      metadata: { userId: 'user-1', orderId: 'order-1' },
      ...overrides,
    };
  }

  // =========================================================================
  // Email channel — end to end
  // =========================================================================
  describe('Email channel end-to-end', () => {
    it('should deliver email when preferences allow it', async () => {
      const record = await notificationService.send(makePayload());

      expect(record.success).toBe(true);
      expect(record.suppressed).toBe(false);
      expect(record.channel).toBe('email');

      // Adapter received the email
      const sent = emailAdapter.getSentEmails();
      expect(sent).toHaveLength(1);
      expect(sent[0].to).toBe('alice@example.com');

      // History logged as delivered
      const logs = historyService.getByRecipient('alice@example.com');
      expect(logs).toHaveLength(1);
      expect(logs[0].status).toBe('delivered');
      expect(logs[0].channel).toBe('email');
    });

    it('should suppress email when user has email disabled', async () => {
      // Explicitly disable email for this user
      preferencesService.updateEmailPreferences('user-1', { enabled: false });

      const record = await notificationService.send(makePayload());

      expect(record.success).toBe(false);
      expect(record.suppressed).toBe(true);

      // Adapter should NOT have been called
      expect(emailAdapter.getSentEmails()).toHaveLength(0);

      // History logged as suppressed
      const logs = historyService.getByRecipient('alice@example.com');
      expect(logs).toHaveLength(1);
      expect(logs[0].status).toBe('suppressed');
    });

    it('should suppress email when notification type is unsubscribed', async () => {
      preferencesService.updateEmailPreferences('user-1', {
        subscribedCategories: ['system-alert'], // only subscribed to system-alert
      });

      const record = await notificationService.send(makePayload({
        notificationType: 'order-confirmation',
      }));

      expect(record.suppressed).toBe(true);
      expect(emailAdapter.getSentEmails()).toHaveLength(0);
    });
  });

  // =========================================================================
  // SMS channel — end to end
  // =========================================================================
  describe('SMS channel end-to-end', () => {
    it('should deliver SMS when preferences allow it', async () => {
      // SMS is disabled by default — enable it
      preferencesService.updateSMSPreferences('user-1', { enabled: true });

      const record = await notificationService.send(makePayload({
        channel: 'sms',
        recipient: '+15551234567',
      }));

      expect(record.success).toBe(true);
      expect(record.suppressed).toBe(false);
      expect(record.channel).toBe('sms');

      // Adapter received the SMS
      const sent = smsAdapter.getSentMessages();
      expect(sent).toHaveLength(1);
      expect(sent[0].to).toBe('+15551234567');

      // History logged
      const logs = historyService.getByRecipient('+15551234567');
      expect(logs).toHaveLength(1);
      expect(logs[0].status).toBe('delivered');
      expect(logs[0].channel).toBe('sms');
    });

    it('should suppress SMS when SMS channel is disabled (default)', async () => {
      // SMS is disabled by default — don't enable it
      // But we need preferences to exist for the user so the check runs
      preferencesService.getOrCreatePreferences('user-1');

      const record = await notificationService.send(makePayload({
        channel: 'sms',
        recipient: '+15551234567',
      }));

      expect(record.suppressed).toBe(true);
      expect(smsAdapter.getSentMessages()).toHaveLength(0);

      // Suppressed notifications should still be logged in history
      const logs = historyService.getByRecipient('+15551234567');
      expect(logs).toHaveLength(1);
      expect(logs[0].status).toBe('suppressed');
    });
  });

  // =========================================================================
  // Webhook channel — end to end
  // =========================================================================
  describe('Webhook channel end-to-end', () => {
    it('should deliver webhook when preferences allow it', async () => {
      preferencesService.updateWebhookPreferences('user-1', { enabled: true });

      const record = await notificationService.send(makePayload({
        channel: 'webhook',
        recipient: 'https://example.com/hook',
      }));

      expect(record.success).toBe(true);
      expect(record.channel).toBe('webhook');

      const delivered = webhookAdapter.getDeliveredWebhooks();
      expect(delivered).toHaveLength(1);
      expect(delivered[0].url).toBe('https://example.com/hook');

      // History logged
      const logs = historyService.getByRecipient('https://example.com/hook');
      expect(logs).toHaveLength(1);
      expect(logs[0].status).toBe('delivered');
    });

    it('should suppress webhook when channel is disabled (default)', async () => {
      preferencesService.getOrCreatePreferences('user-1');

      const record = await notificationService.send(makePayload({
        channel: 'webhook',
        recipient: 'https://example.com/hook',
      }));

      expect(record.suppressed).toBe(true);
      expect(webhookAdapter.getDeliveredWebhooks()).toHaveLength(0);
    });
  });

  // =========================================================================
  // History tracking across channels
  // =========================================================================
  describe('History tracking', () => {
    it('should log all notifications in history with correct statuses', async () => {
      // Enable SMS and webhook for this user
      preferencesService.updateSMSPreferences('user-1', { enabled: true });
      preferencesService.updateWebhookPreferences('user-1', { enabled: true });

      // Send one via each channel
      await notificationService.send(makePayload({ channel: 'email', recipient: 'alice@example.com' }));
      await notificationService.send(makePayload({ channel: 'sms', recipient: '+15551234567' }));
      await notificationService.send(makePayload({ channel: 'webhook', recipient: 'https://example.com/hook' }));

      const all = historyService.getAll();
      expect(all).toHaveLength(3);
      expect(all.every((l) => l.status === 'delivered')).toBe(true);

      // Each channel should have exactly one log
      const emailLogs = historyService.query({ channel: 'email' });
      const smsLogs = historyService.query({ channel: 'sms' });
      const webhookLogs = historyService.query({ channel: 'webhook' });
      expect(emailLogs).toHaveLength(1);
      expect(smsLogs).toHaveLength(1);
      expect(webhookLogs).toHaveLength(1);
    });

    it('should log both delivered and suppressed notifications', async () => {
      // Enable email, leave SMS disabled
      preferencesService.getOrCreatePreferences('user-1');

      await notificationService.send(makePayload({ channel: 'email', recipient: 'alice@example.com' }));
      await notificationService.send(makePayload({ channel: 'sms', recipient: '+15551234567' }));

      const all = historyService.getAll();
      expect(all).toHaveLength(2);

      const delivered = historyService.query({ status: 'delivered' });
      const suppressed = historyService.query({ status: 'suppressed' });
      expect(delivered).toHaveLength(1);
      expect(delivered[0].channel).toBe('email');
      expect(suppressed).toHaveLength(1);
      expect(suppressed[0].channel).toBe('sms');
    });

    it('should log failed notifications when adapter returns failure', async () => {
      // No adapter registered for in-app channel
      const record = await notificationService.send(makePayload({
        channel: 'in-app',
        recipient: 'user-1',
      }));

      expect(record.success).toBe(false);
      expect(record.suppressed).toBe(false);

      // Failed notifications are logged via the notification:failed event
      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0].status).toBe('failed');
      expect(logs[0].channel).toBe('in-app');
    });
  });

  // =========================================================================
  // Preferences are respected per-channel independently
  // =========================================================================
  describe('Channel independence', () => {
    it('should allow email but suppress SMS for the same user and notification type', async () => {
      // Email enabled (default), SMS disabled (default)
      preferencesService.getOrCreatePreferences('user-1');

      const emailResult = await notificationService.send(makePayload({
        channel: 'email',
        recipient: 'alice@example.com',
      }));
      const smsResult = await notificationService.send(makePayload({
        channel: 'sms',
        recipient: '+15551234567',
      }));

      expect(emailResult.success).toBe(true);
      expect(emailResult.suppressed).toBe(false);
      expect(smsResult.suppressed).toBe(true);

      expect(emailAdapter.getSentEmails()).toHaveLength(1);
      expect(smsAdapter.getSentMessages()).toHaveLength(0);
    });

    it('should allow disabling email while enabling SMS', async () => {
      preferencesService.updateEmailPreferences('user-1', { enabled: false });
      preferencesService.updateSMSPreferences('user-1', { enabled: true });

      const emailResult = await notificationService.send(makePayload({
        channel: 'email',
        recipient: 'alice@example.com',
      }));
      const smsResult = await notificationService.send(makePayload({
        channel: 'sms',
        recipient: '+15551234567',
      }));

      expect(emailResult.suppressed).toBe(true);
      expect(smsResult.success).toBe(true);
      expect(smsResult.suppressed).toBe(false);
    });
  });

  // =========================================================================
  // Notification ordering
  // =========================================================================
  describe('Notification ordering', () => {
    it('should deliver notifications to the same recipient in send order', async () => {
      const results = await Promise.all([
        notificationService.send(makePayload({ subject: 'First', recipient: 'alice@example.com' })),
        notificationService.send(makePayload({ subject: 'Second', recipient: 'alice@example.com' })),
        notificationService.send(makePayload({ subject: 'Third', recipient: 'alice@example.com' })),
      ]);

      expect(results[0].subject).toBe('First');
      expect(results[1].subject).toBe('Second');
      expect(results[2].subject).toBe('Third');

      // Verify adapter received them in order
      const sent = emailAdapter.getSentEmails();
      expect(sent).toHaveLength(3);
      expect(sent[0].subject).toBe('First');
      expect(sent[1].subject).toBe('Second');
      expect(sent[2].subject).toBe('Third');

      // Verify history records ordering
      const logs = historyService.getByRecipient('alice@example.com');
      expect(logs).toHaveLength(3);
      expect(logs[0].subject).toBe('First');
      expect(logs[1].subject).toBe('Second');
      expect(logs[2].subject).toBe('Third');
    });

    it('should not block notifications across different recipients', async () => {
      preferencesService.updateSMSPreferences('user-1', { enabled: true });

      const [emailResult, smsResult] = await Promise.all([
        notificationService.send(makePayload({ channel: 'email', recipient: 'alice@example.com' })),
        notificationService.send(makePayload({ channel: 'sms', recipient: '+15551234567' })),
      ]);

      // Both should succeed independently
      expect(emailResult.success).toBe(true);
      expect(smsResult.success).toBe(true);

      expect(emailAdapter.getSentEmails()).toHaveLength(1);
      expect(smsAdapter.getSentMessages()).toHaveLength(1);
    });
  });

  // =========================================================================
  // Full pipeline — multiple users, channels, preferences
  // =========================================================================
  describe('Multi-user multi-channel pipeline', () => {
    it('should handle mixed preferences across users and channels', async () => {
      // User 1: email on, SMS off (defaults)
      preferencesService.getOrCreatePreferences('user-1');

      // User 2: email off, SMS on, webhook on
      preferencesService.updateEmailPreferences('user-2', { enabled: false });
      preferencesService.updateSMSPreferences('user-2', { enabled: true });
      preferencesService.updateWebhookPreferences('user-2', { enabled: true });

      // User 1 email — delivered
      const u1Email = await notificationService.send(makePayload({
        channel: 'email',
        recipient: 'alice@example.com',
        metadata: { userId: 'user-1' },
      }));
      // User 1 SMS — suppressed (default disabled)
      const u1SMS = await notificationService.send(makePayload({
        channel: 'sms',
        recipient: '+15551111111',
        metadata: { userId: 'user-1' },
      }));
      // User 2 email — suppressed
      const u2Email = await notificationService.send(makePayload({
        channel: 'email',
        recipient: 'bob@example.com',
        metadata: { userId: 'user-2' },
      }));
      // User 2 SMS — delivered
      const u2SMS = await notificationService.send(makePayload({
        channel: 'sms',
        recipient: '+15552222222',
        metadata: { userId: 'user-2' },
      }));
      // User 2 webhook — delivered
      const u2Webhook = await notificationService.send(makePayload({
        channel: 'webhook',
        recipient: 'https://bob.example.com/hook',
        metadata: { userId: 'user-2' },
      }));

      expect(u1Email.success).toBe(true);
      expect(u1SMS.suppressed).toBe(true);
      expect(u2Email.suppressed).toBe(true);
      expect(u2SMS.success).toBe(true);
      expect(u2Webhook.success).toBe(true);

      // Verify adapter call counts
      expect(emailAdapter.getSentEmails()).toHaveLength(1);
      expect(smsAdapter.getSentMessages()).toHaveLength(1);
      expect(webhookAdapter.getDeliveredWebhooks()).toHaveLength(1);

      // Verify full history
      const all = historyService.getAll();
      expect(all).toHaveLength(5);
      const deliveredCount = all.filter((l) => l.status === 'delivered').length;
      const suppressedCount = all.filter((l) => l.status === 'suppressed').length;
      expect(deliveredCount).toBe(3);
      expect(suppressedCount).toBe(2);
    });
  });

  // =========================================================================
  // No preferences = allow all (backward compatibility)
  // =========================================================================
  describe('No preferences (backward compatibility)', () => {
    it('should deliver to all channels when user has no preferences', async () => {
      // Don't create any preferences for user-1
      const emailResult = await notificationService.send(makePayload({
        channel: 'email',
        recipient: 'newuser@example.com',
      }));
      const smsResult = await notificationService.send(makePayload({
        channel: 'sms',
        recipient: '+15559999999',
      }));
      const webhookResult = await notificationService.send(makePayload({
        channel: 'webhook',
        recipient: 'https://newuser.example.com/hook',
      }));

      expect(emailResult.success).toBe(true);
      expect(smsResult.success).toBe(true);
      expect(webhookResult.success).toBe(true);

      expect(emailAdapter.getSentEmails()).toHaveLength(1);
      expect(smsAdapter.getSentMessages()).toHaveLength(1);
      expect(webhookAdapter.getDeliveredWebhooks()).toHaveLength(1);
    });
  });
});

